<?php require_once __DIR__.'/../app/bootstrap.php'; if(!installed()) redirect('/install/'); $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $st=db()->prepare('SELECT * FROM admins WHERE username=?'); $st->execute([$_POST['username']??'']); $u=$st->fetch(); if($u&&password_verify((string)$_POST['password'],$u['password_hash'])){session_regenerate_id(true);$_SESSION['admin_id']=$u['id'];redirect('/admin/');} $err='ログインに失敗しました'; } ?><!doctype html><html lang=ja><head><meta charset=utf-8><link rel=stylesheet href="<?=e(app_url('/assets/admin.css'))?>"><title>Login</title></head><body><main style="margin:0 auto;max-width:420px"><h1>ログイン</h1><?php if($err)echo'<p class="notice error">'.e($err).'</p>';?><form method=post><input name=username placeholder=ユーザー名 required><input type=password name=password placeholder=パスワード required><button>ログイン</button></form></main></body></html>
